  ('public-health-specialist-moex-00551', 'public-health-specialist', 'public-health-specialist-moex-112-8041b019', 'sub-public-health-specialist-04', NULL, 'single_choice', '某研究者收集了 10 名罕見疾病患者的發病年齡，若欲比較男性和女性之發病年齡是否有差 異，則該使用何種統計方法來進行檢定？', '["Kruskal-wallistest", "Wilcoxonrank-sumtest", "Wilcoxonsign-rankedtest", "Spearmancorrelation"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:38+00:00", "source_pdf_sha1": "d294e494c96d", "answer_pdf_sha1": "9af26e798d31", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "108", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生物統計學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
